-- Helper: send JSON response
local function send_json_response(status, data)
    ngx.status = status
    ngx.header["Content-Type"] = "application/json; charset=utf-8"
    ngx.say(cjson.encode(data))
    return ngx.exit(status)
end

-- Helper: connect to Redis
local function connect_redis()
    local red, err = redis:new()
    if not red then
        return nil, "Failed to create Redis instance: " .. (err or "unknown")
    end

    red:set_timeout(REDIS_TIMEOUT)

    local ok, err = red:connect(REDIS_HOST, REDIS_PORT)
    if not ok then
        return nil, "Failed to connect to Redis: " .. (err or "unknown")
    end

    if REDIS_PASSWORD and REDIS_PASSWORD ~= "" then
        local res, err = red:auth(REDIS_PASSWORD)
        if not res then
            return nil, "Failed to authenticate with Redis: " .. (err or "unknown")
        end
    end

    return red, nil
end

-- Helper: return Redis connection to pool
local function keepalive_redis(red)
    if not red then
        return
    end
    local ok, err = red:set_keepalive(REDIS_KEEPALIVE_TIMEOUT, REDIS_KEEPALIVE_POOL_SIZE)
    if not ok then
        ngx.log(ngx.WARN, "Failed to set Redis keepalive: ", err)
    end
end

-- Helper: parse arguments from various formats
local function parse_args(args_param)
    if not args_param then
        return {}
    end

    -- If it's already a table (from JSON body), return as-is
    if type(args_param) == "table" then
        return args_param
    end

    -- Try JSON parsing first
    local ok, parsed = pcall(cjson.decode, args_param)
    if ok and type(parsed) == "table" then
        return parsed
    end

    -- Fall back to space-separated string parsing (respecting quotes)
    local args = {}
    local current = ""
    local in_quotes = false
    local quote_char = nil

    for i = 1, #args_param do
        local c = args_param:sub(i, i)
        if in_quotes then
            if c == quote_char then
                in_quotes = false
            else
                current = current .. c
            end
        elseif c == '"' or c == "'" then
            in_quotes = true
            quote_char = c
        elseif c == ' ' or c == '\t' then
            if #current > 0 then
                args[#args + 1] = current
                current = ""
            end
        else
            current = current .. c
        end
    end
    if #current > 0 then
        args[#args + 1] = current
    end

    return args
end

-- Helper: format Redis response for JSON serialization
local function format_redis_response(res)
    if type(res) == "userdata" then
        -- ngx.null
        return cjson.null
    elseif type(res) == "table" then
        local formatted = {}
        for i, v in ipairs(res) do
            formatted[i] = format_redis_response(v)
        end
        return formatted
    else
        return res
    end
end

-- Validate command against blacklist
local function validate_command(cmd)
    if not cmd or cmd == "" then
        return false, "Command is required"
    end

    local lower_cmd = string.lower(cmd)
    if BLOCKED_COMMANDS[lower_cmd] then
        return false, "Command '" .. cmd .. "' is blocked for security reasons"
    end

    return true, nil
end

-- Execute a standard Redis command dynamically
local function execute_command(red, command, args)
    local lower_cmd = string.lower(command)

    -- Use red[command] dynamically
    local cmd_func = red[lower_cmd]
    if not cmd_func then
        return nil, "Unknown Redis command: " .. command
    end

    local res, err
    if #args == 0 then
        res, err = cmd_func(red)
    else
        res, err = cmd_func(red, unpack(args))
    end

    return res, err
end

-- Execute EVAL command
local function execute_eval(red, script, keys, argv)
    keys = keys or {}
    argv = argv or {}

    local num_keys = #keys

    -- Build the full argument list: numkeys, key1, key2, ..., arg1, arg2, ...
    local eval_args = { script, num_keys }
    for _, k in ipairs(keys) do
        eval_args[#eval_args + 1] = k
    end
    for _, a in ipairs(argv) do
        eval_args[#eval_args + 1] = a
    end

    local res, err = red:eval(unpack(eval_args))
    return res, err
end

-- Execute pipeline of commands
local function execute_pipeline(red, commands)
    red:init_pipeline()

    for i, cmd_entry in ipairs(commands) do
        local command = cmd_entry.command or cmd_entry.cmd
        if not command then
            return nil, "Pipeline command #" .. i .. " missing 'command' field"
        end

        local valid, verr = validate_command(command)
        if not valid then
            return nil, "Pipeline command #" .. i .. ": " .. verr
        end

        local args = parse_args(cmd_entry.args)
        local lower_cmd = string.lower(command)
        local cmd_func = red[lower_cmd]
        if not cmd_func then
            return nil, "Unknown Redis command in pipeline #" .. i .. ": " .. command
        end

        if #args == 0 then
            cmd_func(red)
        else
            cmd_func(red, unpack(args))
        end
    end

    local results, err = red:commit_pipeline()
    return results, err
end

