-- Authentication middleware (optional, enable via env var)
local function check_auth()
    local api_key = os.getenv("REDIS_API_KEY")
    if not api_key or api_key == "" then
        return true
    end

    local provided_key = ngx.req.get_headers()["X-API-Key"]
        or ngx.req.get_headers()["Authorization"]
        or ngx.req.get_uri_args()["api_key"]

    -- Handle Bearer token format
    if provided_key and provided_key:sub(1, 7) == "Bearer " then
        provided_key = provided_key:sub(8)
    end

    if provided_key ~= api_key then
        return send_json_response(401, {
            success = false,
            error = "Unauthorized. Provide valid API key via X-API-Key header."
        })
    end

    return true
end

-- Rate limiting (simple, per-IP, using shared dict)
local function check_rate_limit()
    local limit_dict = ngx.shared.redis_api_limit
    if not limit_dict then
        return true  -- No shared dict configured, skip rate limiting
    end

    local client_ip = ngx.var.remote_addr
    local key = "rate:" .. client_ip
    local max_requests = 100  -- per window
    local window = 60  -- seconds

    local current, err = limit_dict:incr(key, 1, 0, window)
    if not current then
        ngx.log(ngx.WARN, "Rate limit incr failed: ", err)
        return true
    end

    if current > max_requests then
        ngx.header["Retry-After"] = window
        return send_json_response(429, {
            success = false,
            error = "Rate limit exceeded. Max " .. max_requests .. " requests per " .. window .. " seconds.",
            retry_after = window
        })
    end

    ngx.header["X-RateLimit-Limit"] = max_requests
    ngx.header["X-RateLimit-Remaining"] = math.max(0, max_requests - current)

    return true
end

